const item = $input.first()?.json ?? {};

if (!item.batch_id) {
  return [{
    json: {
      ...item,
      batchDatasetSql: "select NULL::bigint as batch_id, 'No new signups available'::text as message;",
    },
  }];
}

const batchId = Number(item.batch_id);

return [{
  json: {
    ...item,
    batchDatasetSql: `select
    ${batchId}::bigint as batch_id,
    to_char(i.item_date, 'dd-MM-yyyy hh24:mi') as item_date,
    i.source,
    i.member,
    i.payer,
    coalesce(i.product, 'Manual batch item') as product,
    i.regular_tags,
    i.parent_tags,
    i.key_tags,
    i.email_address,
    i.address_1,
    i.address_2,
    i.address_3,
    i.town,
    i.postcode
from public.vw_signup_batch_items as i
where i.batch_id = ${batchId}
order by i.item_date, i.member, i.source_id;`,
  },
}];

const rows = $input.all().map((item) => item.json ?? {});
const first = rows[0] ?? {};

if (!rows.length || !first.batch_id) {
  return [{
    json: {
      batch_id: first.batch_id ?? null,
      row_count: 0,
      message: first.message ?? 'No new signups available',
    },
  }];
}

const headers = [
  'item_date',
  'source',
  'member',
  'payer',
  'product',
  'regular_tags',
  'parent_tags',
  'key_tags',
  'email_address',
  'address_1',
  'address_2',
  'address_3',
  'town',
  'postcode',
];

const csvEscape = (value) => {
  if (value === null || value === undefined) return '';
  const stringValue = String(value);
  if (/[",\n\r]/.test(stringValue)) {
    return `"${stringValue.replace(/"/g, '""')}"`;
  }
  return stringValue;
};

const lines = [headers.map(csvEscape).join(',')];
for (const row of rows) {
  lines.push(headers.map((header) => csvEscape(row[header])).join(','));
}

const batchId = Number(first.batch_id);
const fileName = `signup-batch-${batchId}.csv`;
const csv = lines.join('\n');

return [{
  json: {
    batch_id: batchId,
    row_count: rows.length,
    file_name: fileName,
  },
  binary: {
    data: {
      data: Buffer.from(csv, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName,
      fileExtension: 'csv',
    },
  },
}];

